const lista = $json.lista_precos;
if (!lista || !Array.isArray(lista)) throw new Error('Campo lista_precos ausente ou invalido.');
return lista.map(item => ({ json: item, pairedItem: { item: 0 } }));

// Agrupa por produto+atributos e aplica formula de precificacao
const items = $input.all().map(i => i.json);

const grupos = {};
for (const item of items) {
  const chave = item.modeloSite + '|' + JSON.stringify(item.atributos || {});
  if (!grupos[chave]) {
    grupos[chave] = {
      modeloSite: item.modeloSite,
      atributos:  item.atributos || {},
      precos: []
    };
  }
  if (item.preco > 0) grupos[chave].precos.push(Number(item.preco));
}

const resultados = [];
for (const g of Object.values(grupos)) {
  if (g.precos.length === 0) continue;
  const menor = Math.min(...g.precos);
  const maior = Math.max(...g.precos);
  const variacao = maior - menor;
  let preco, preco_atacado;

  if (g.modeloSite.toLowerCase().includes('iphone')) {
    // Formula iPhone: varejo = min(maior+50, menor+65)
    preco = Math.min(maior + 50, menor + 65);
    // Atacado em degraus
    if (variacao <= 35)      preco_atacado = maior + 15;
    else if (variacao <= 50) preco_atacado = maior + 10;
    else                     preco_atacado = maior + 5;
  } else {
    // Formula farmacos: varejo = maior+12, atacado = maior+5
    preco = maior + 12;
    preco_atacado = maior + 5;
  }

  resultados.push({
    json: {
      modeloSite:       g.modeloSite,
      atributos:        g.atributos,
      preco,
      preco_atacado,
      preco_compra:     menor,
      preco_maior:      maior,
      variacao,
      num_fornecedores: g.precos.length
    },
    pairedItem: { item: 0 }
  });
}

return resultados;

const lista = $input.all().map(i => i.json);
const src = $('Loop Produtos').item.json;
function norm(s){ return (s||'').toLowerCase().replace(/\s+/g,' ').trim(); }
const n0=norm(src.modeloSite);
const wPM=n0.includes('pro max');
const wP=!wPM&&n0.includes('pro');
const wAir=n0.includes('air');
const wE=/\d+e\b/.test(n0);
const wPL=n0.includes('plus');
let best=null,pts=-1;
for(const item of lista){
  const n1=norm(item.name||'');
  const hPM=n1.includes('pro max');
  const hP=!hPM&&n1.includes('pro');
  const hAir=n1.includes('air');
  const hE=/\d+e\b/.test(n1);
  const hPL=n1.includes('plus');
  if(hPM&&!wPM)continue;
  if(hP&&!wP)continue;
  if(hAir&&!wAir)continue;
  if(hPL&&!wPL)continue;
  if(wPM&&!hPM)continue;
  if(wP&&!hP)continue;
  if(wAir&&!hAir)continue;
  if(wE&&!hE)continue;
  if(!wE&&hE)continue;
  let p=0;
  for(const w of n0.split(' '))if(n1.includes(w))p++;
  if(p>pts){pts=p;best=item;}
}
if(!best)return[{json:{skip:true,motivo:'produto_nao_encontrado',modeloSite:src.modeloSite},pairedItem:{item:0}}];
return[{json:{...src,pai_id:best.id,pai_nome:best.name},pairedItem:{item:0}}];

const vars=$input.all().map(i=>i.json);
const src=$('Loop Produtos').item.json;
const atrs=src.atributos||{};
function nv(s){return (s||'').toString().toUpperCase().replace(/\s+/g,'');}
function match(v,attrs){
  for(const [k,val] of Object.entries(attrs)){
    const kn=nv(k); const vn=nv(val);
    const ok=(v.attributes||[]).some(a=>
      (nv(a.name)===kn||nv(a.slug).replace(/-/g,'').includes(kn.toLowerCase().replace(/\s/g,''))) && nv(a.option)===vn
    );
    if(!ok)return false;
  }
  return true;
}
const found=vars.filter(v=>match(v,atrs));
if(found.length===0)return[{json:{skip:true,motivo:'variacao_nao_encontrada',atributos:atrs,pai_nome:src.pai_nome},pairedItem:{item:0}}];
return found.map(v=>({json:{...src,var_id:v.id,preco_atual:v.regular_price},pairedItem:{item:0}}));
